import{_ as e,o as a,c as t,ag as i}from"./chunks/framework-C5-Jzrz4.js";const o=JSON.parse('{"title":"登录页面架构分析","description":"认证布局、通用登录组件与应用层业务定制关系","frontmatter":{"title":"登录页面架构分析","description":"认证布局、通用登录组件与应用层业务定制关系","lastUpdated":true},"headers":[],"relativePath":"scripts/analysis/登录页面架构分析.md","filePath":"scripts/analysis/登录页面架构分析.md","lastUpdated":null}');const l=e({name:"scripts/analysis/登录页面架构分析.md"},[["render",function(e,o,l,d,c,r){return a(),t("div",null,[...o[0]||(o[0]=[i('<h1 id="登录页面架构分析" tabindex="-1">登录页面架构分析 <a class="header-anchor" href="#登录页面架构分析" aria-label="Permalink to &quot;登录页面架构分析&quot;">​</a></h1><h2 id="简介" tabindex="-1">简介 <a class="header-anchor" href="#简介" aria-label="Permalink to &quot;简介&quot;">​</a></h2><p>登录页采用“布局层 + 通用 UI 层 + 应用业务层”分层组合，既复用通用能力，又保留租户、验证码、第三方登录等业务差异。</p><h2 id="适用范围" tabindex="-1">适用范围 <a class="header-anchor" href="#适用范围" aria-label="Permalink to &quot;适用范围&quot;">​</a></h2><ul><li>登录页问题排查</li><li>新增登录方式（短信、社交等）扩展</li><li>分层职责确认</li></ul><h2 id="对应源码目录或关键文件" tabindex="-1">对应源码目录或关键文件 <a class="header-anchor" href="#对应源码目录或关键文件" aria-label="Permalink to &quot;对应源码目录或关键文件&quot;">​</a></h2><ul><li><code>apps/web-antd/src/views/_core/authentication/login.vue</code></li><li><code>apps/web-antd/src/layouts/auth.vue</code></li><li><code>packages/effects/layouts/src/authentication/*</code></li><li><code>packages/effects/common-ui/src/ui/authentication/*</code></li><li><code>apps/web-antd/src/store/auth.ts</code></li><li><code>apps/web-antd/src/api/core/{auth,captcha}.ts</code></li></ul><h2 id="核心机制或功能说明" tabindex="-1">核心机制或功能说明 <a class="header-anchor" href="#核心机制或功能说明" aria-label="Permalink to &quot;核心机制或功能说明&quot;">​</a></h2><h3 id="组件分层" tabindex="-1">组件分层 <a class="header-anchor" href="#组件分层" aria-label="Permalink to &quot;组件分层&quot;">​</a></h3><table tabindex="0"><thead><tr><th>层级</th><th>主要文件</th><th>职责</th></tr></thead><tbody><tr><td>布局层</td><td><code>packages/effects/layouts/src/authentication/authentication.vue</code></td><td>logo、工具栏、认证页整体布局</td></tr><tr><td>通用登录 UI 层</td><td><code>packages/effects/common-ui/src/ui/authentication/*</code></td><td>登录表单渲染、交互容器、基础提交逻辑</td></tr><tr><td>应用业务层</td><td><code>apps/web-antd/src/views/_core/authentication/login.vue</code></td><td>租户、验证码、OAuth 等项目定制</td></tr></tbody></table><h3 id="登录主流程" tabindex="-1">登录主流程 <a class="header-anchor" href="#登录主流程" aria-label="Permalink to &quot;登录主流程&quot;">​</a></h3><ol><li>页面加载时请求租户列表与验证码（按配置决定显示）</li><li>用户提交表单后调用 <code>useAuthStore().authLogin(...)</code></li><li><code>authLogin</code> 内部： <ul><li>调 <code>loginApi</code></li><li>写入 token（<code>useAccessStore</code>）</li><li>调 <code>fetchUserInfo</code></li><li>设置权限码并跳转首页</li></ul></li></ol><h3 id="关键扩展点" tabindex="-1">关键扩展点 <a class="header-anchor" href="#关键扩展点" aria-label="Permalink to &quot;关键扩展点&quot;">​</a></h3><ul><li>表单组件与字段通过 Schema 生成（由通用登录组件承载）</li><li>第三方登录通过业务层 slot/组件插入</li><li>租户逻辑由 <code>tenantList()</code> + <code>useTenantStore</code> 驱动</li></ul><h2 id="使用方式、扩展方式或注意事项" tabindex="-1">使用方式、扩展方式或注意事项 <a class="header-anchor" href="#使用方式、扩展方式或注意事项" aria-label="Permalink to &quot;使用方式、扩展方式或注意事项&quot;">​</a></h2><ul><li>新增登录方式优先扩展应用层参数组装，避免直接改通用层基础协议。</li><li>登录流程问题优先检查： <ul><li><code>api/core/auth.ts</code></li><li><code>store/auth.ts</code></li><li>路由守卫 <code>router/guard.ts</code></li></ul></li><li>若出现“登录成功但菜单不加载”，重点检查 token、<code>fetchUserInfo</code> 与 <code>generateAccess</code> 调用链。</li></ul>',16)])])}]]);export{o as __pageData,l as default};
